import { Loader2 } from "lucide-react";
import { dashSectionCard } from "@/lib/dashboardUi";
import { cn } from "@/lib/utils";

export type PageLoaderProps = {
  message: string;
  /** Full viewport — root redirect, session gate, public auth redirect. */
  fullScreen?: boolean;
  /** Dashboard-style bordered card (form pages while fetching). */
  inCard?: boolean;
  /** Two pulse bars under the message (edit/detail placeholders). */
  withFormSkeleton?: boolean;
  /** Tighter layout for Suspense fallbacks inside smaller regions. */
  compact?: boolean;
  className?: string;
};

/**
 * Shared loading UI for redirects, auth checks, Suspense fallbacks, and data fetches.
 * Uses live region semantics so screen readers announce the loading state.
 */
export function PageLoader({
  message,
  fullScreen = false,
  inCard = false,
  withFormSkeleton = false,
  compact = false,
  className
}: PageLoaderProps) {
  const iconWrap = cn(
    "flex shrink-0 items-center justify-center rounded-2xl bg-primary/[0.09] shadow-[inset_0_1px_0_0_rgba(255,255,255,0.06)]",
    compact ? "size-11" : "size-14"
  );
  const icon = cn("animate-spin text-primary", compact ? "size-5" : "size-7");

  const body = (
    <div
      className={cn(
        "flex flex-col items-center text-center",
        compact ? "gap-3" : "gap-4",
        inCard && "px-6 pt-8",
        inCard && withFormSkeleton && "pb-2"
      )}
    >
      <div className={iconWrap} aria-hidden>
        <Loader2 className={icon} />
      </div>
      <p
        className={cn(
          "max-w-xs text-pretty text-muted-foreground",
          compact ? "text-xs leading-snug" : "text-sm leading-relaxed"
        )}
      >
        {message}
      </p>
    </div>
  );

  const skeleton =
    withFormSkeleton && inCard ? (
      <div className="space-y-3 border-t border-border/70 px-6 pb-8 pt-6" aria-hidden>
        <div className="h-10 w-full animate-pulse rounded-lg bg-muted/80" />
        <div className="h-24 w-full animate-pulse rounded-lg bg-muted/80" />
      </div>
    ) : null;

  const inner =
    inCard || withFormSkeleton ? (
      <div className={cn(dashSectionCard, "overflow-hidden shadow-card")}>
        {body}
        {skeleton}
      </div>
    ) : (
      body
    );

  return (
    <div
      role="status"
      aria-live="polite"
      aria-busy="true"
      className={cn(
        fullScreen &&
          "flex min-h-screen flex-col items-center justify-center bg-gradient-to-b from-background via-background to-muted/25 px-6 py-16",
        !fullScreen && "flex flex-col items-center justify-center",
        !fullScreen && !inCard && !withFormSkeleton && (compact ? "min-h-[100px] py-10" : "py-20 md:py-24"),
        !fullScreen && (inCard || withFormSkeleton) && "w-full",
        className
      )}
    >
      <span className="sr-only">{message}</span>
      {inner}
    </div>
  );
}

